import { writeFileSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';
const __dirname = dirname(fileURLToPath(import.meta.url));
const w = (dir, slug, obj) => {
  mkdirSync(join(__dirname, dir), { recursive: true });
  writeFileSync(join(__dirname, dir, slug + '.json'), JSON.stringify(obj, null, 2));
  console.log('  ✓ ' + slug);
};
console.log('\n=== profiles_v12 (Judaism - political & advocacy) ===');

w('profiles_v12','aipac',{"brand_name":"AIPAC","brand_slug":"aipac","parent_company":"American Israel Public Affairs Committee","ultimate_parent":"American Israel Public Affairs Committee","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"AIPAC SPENT $100 MILLION IN THE 2022 MIDTERMS TO DEFEAT PROGRESSIVE DEMOCRATS — IT STILL CLAIMS IT IS NOT A POLITICAL ACTION COMMITTEE — AND DEBATE OVER WHETHER IT SHOULD REGISTER AS A FOREIGN AGENT HAS RUN FOR 60 YEARS","executive_summary":"The American Israel Public Affairs Committee (AIPAC) is the largest pro-Israel lobbying organization in the United States, with a declared membership of approximately 3 million people and annual revenue exceeding $100 million. In the 2022 midterm elections, AIPAC's affiliated super PAC — the United Democracy Project — spent approximately $100 million, primarily targeting progressive Democratic candidates who were critical of Israeli government policies, including Reps. Andy Levin and Summer Lee. This represented a dramatic expansion from AIPAC's historic non-electoral posture. The debate over whether AIPAC should register as a foreign agent under the Foreign Agents Registration Act (FARA) — given that it advocates for the policies of a foreign government — has been ongoing since the 1960s when the Kennedy administration investigated its predecessor organization, the American Zionist Council.","verdict_tags":["100m_2022_midterms_progressive_targeting","united_democracy_project_super_pac","fara_foreign_agent_debate_60_years","kennedy_investigation_predecessor","3_million_declared_members","no_electoral_disclosure_historically","andy_levin_summer_lee_targeting","bipartisan_congressional_access_documented"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"AIPAC employs approximately 400 staff. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"AIPAC does not take positions on US domestic environmental policy. Its advocacy is focused on US-Israel relations.","flags":[],"sources":[]},"political":{"summary":"AIPAC is the most powerful single-issue lobby in Washington by most assessments. Its annual policy conference attracts the majority of Congress and every presidential candidate. Its documented influence operates through: direct lobbying of members of Congress and executive branch officials; cultivating congressional relationships through AIPAC-sponsored trips to Israel; and since 2022, direct electoral intervention through the United Democracy Project super PAC. The 2022 intervention — spending $100 million primarily to defeat progressive Democrats critical of Israeli government policy — represented a strategic shift from AIPAC's historic non-electoral posture and generated significant internal debate. AIPAC has been the subject of FARA registration debates since the Kennedy administration investigated its predecessor organization in the early 1960s; it has never been required to register.","flags":["100m_2022_electoral_intervention_progressive_targeting","fara_registration_never_required_debated_60_years","congressional_israel_trips_documented","policy_conference_majority_congress_attendance","kennedy_predecessor_investigation"],"sources":[]},"legal":{"summary":"AIPAC has never been required to register as a foreign agent under FARA despite decades of debate. The Kennedy administration's 1961-1963 investigation of AIPAC's predecessor — the American Zionist Council — led to its dissolution; AIPAC was reorganized in a structure designed to avoid FARA registration. DOJ has not pursued FARA registration against AIPAC. The United Democracy Project super PAC — AIPAC's electoral arm since 2022 — is subject to standard campaign finance disclosure requirements and files with the FEC.","flags":["fara_registration_never_required","kennedy_predecessor_investigation_led_reorganization","udp_fec_disclosed","no_criminal_enforcement"],"sources":[]},"tax":{"summary":"AIPAC itself is a 501(c)(4) social welfare organization — contributions are not tax-deductible. Its educational arm, the AIPAC Foundation, is a 501(c)(3) — contributions are tax-deductible. The United Democracy Project super PAC is separately organized. AIPAC's revenue and expenditures are publicly available through its Form 990 filings. The $100 million in 2022 electoral spending is disclosed in FEC filings.","flags":["501c4_contributions_not_deductible","aipac_foundation_501c3_deductible","udp_fec_disclosed","form_990_public"],"sources":[]},"executives":{"summary":"CEO Howard Kohr has led AIPAC since 1996 — one of the longest tenures of any major advocacy organization CEO. His compensation is publicly disclosed through Form 990 — approximately $1 million annually. The 2022 decision to enter electoral politics through the United Democracy Project represented the most significant strategic shift in AIPAC's history under Kohr's leadership and was controversial within the pro-Israel advocacy community.","flags":["kohr_since_1996_longest_tenures","1m_compensation_form_990","2022_electoral_shift_controversial"],"sources":[]},"connections":{"summary":"AIPAC operates within a broader network of pro-Israel advocacy organizations including the American Jewish Committee, the Jewish Federations of North America, the Conference of Presidents of Major American Jewish Organizations, and JINSA (Jewish Institute for National Security of America). Its relationship with the Israeli government — particularly under different administrations — has varied; AIPAC generally supports Israeli government policy regardless of which party governs Israel.","flags":["broader_pro_israel_network","israel_government_policy_support_regardless_party","conference_presidents_ajc_jinsa_network"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Critics — including some within the Jewish community — have alleged that AIPAC's 2022 electoral intervention specifically targeted progressive Democrats who were not anti-Israel but were critical of specific Israeli government policies, and that framing criticism of Israeli government policy as anti-Israel has a chilling effect on legitimate policy debate. Critics have also alleged that AIPAC's historic non-registration under FARA represents a politically protected exemption not available to other foreign government advocacy organizations. AIPAC disputes both characterizations.","flags":["progressive_targeting_policy_criticism_vs_anti_israel_alleged","fara_politically_protected_exemption_alleged"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against AIPAC have been identified. Its advocacy for US military aid to Israel has downstream connections to the Israeli-Palestinian conflict's human cost, which is a matter of significant international documentation and dispute. These connections are political and contested rather than the kind of direct institutional health harm documented for other organizations in this database.","flags":["us_military_aid_advocacy_conflict_connection_contested"],"sources":[]},"alternatives":{"cheaper":["J Street — self-described pro-Israel, pro-peace advocacy organization with different policy positions","Americans for Peace Now — advocacy for two-state solution","If Not Now — progressive Jewish organization"],"healthier":["Jewish Voice for Peace — progressive Jewish organization opposed to Israeli occupation","J Street — alternative pro-Israel advocacy with different policy positions"],"diy":["AIPAC's Form 990 and the United Democracy Project's FEC filings are publicly available","The DOJ's FARA registration database shows which foreign-government-adjacent organizations have registered"]},"timeline":[{"year":1953,"event":"AIPAC founded as a lobbying organization; predecessor American Zionist Council operates alongside","severity":"neutral","source_url":""},{"year":1961,"event":"Kennedy administration Justice Department investigates American Zionist Council for FARA registration; AZC dissolves; AIPAC reorganized","severity":"critical","source_url":""},{"year":1984,"event":"AIPAC achieves recognition as the dominant pro-Israel lobby following Congressional influence campaigns","severity":"neutral","source_url":""},{"year":2022,"event":"AIPAC creates United Democracy Project super PAC; spends approximately $100M in midterms primarily targeting progressive Democrats","severity":"critical","source_url":""},{"year":2024,"event":"AIPAC continues electoral intervention; spends significant funds in Democratic primaries","severity":"high","source_url":""}],"community_impact":{"displacement":"Progressive Democratic representatives who were defeated in 2022 primaries with significant AIPAC super PAC spending — including Rep. Andy Levin — represented constituencies whose representation was affected by an outside organization's electoral intervention.","price_illusion":"AIPAC presents as a bipartisan organization representing broad Jewish American interests. Its 2022 electoral intervention — targeting progressive Democrats critical of specific Israeli government policies — has been characterized by critics as representing the Israeli government's preferred policy positions more than the diverse range of Jewish American views on Israel.","tax_math":"AIPAC's 501(c)(4) structure allows it to engage in political activity without donor disclosure requirements applicable to PACs. The AIPAC Foundation's 501(c)(3) status allows deductible donations for its educational activities. The United Democracy Project super PAC discloses donors through FEC filings.","wealth_velocity":"AIPAC's $100 million in 2022 electoral spending represents a significant concentration of pro-Israel advocacy resources into electoral intervention. The donors to the United Democracy Project are publicly disclosed through FEC filings."},"cost_absorption":{"who_benefited":[{"group":"Israeli government and right-aligned Israeli policy positions","how":"$100M electoral intervention in 2022 targeted representatives who criticized specific Israeli government policies; bipartisan congressional relationships cultivated over decades"},{"group":"Pro-Israel donor network","how":"Concentrated electoral influence through a single organizational vehicle"}],"who_paid":[{"group":"Progressive Democratic candidates targeted in 2022","how":"Andy Levin and others defeated with significant AIPAC super PAC spending; representatives whose constituencies had elected them replaced"}],"the_gap":"AIPAC spent $100 million in the 2022 midterms. Most of it targeted progressive Democrats who criticized Israeli government policy. Rep. Andy Levin — who described himself as pro-Israel and anti-occupation — was defeated with significant AIPAC spending. AIPAC has been debated as a potential foreign agent since the Kennedy administration. It has never registered under FARA. The debate has been running for 60 years. Howard Kohr has been CEO for 28 years and makes $1 million a year."}});

w('profiles_v12','zionist-organization-of-america',{"brand_name":"Zionist Organization of America","brand_slug":"zionist-organization-of-america","parent_company":"Zionist Organization of America","ultimate_parent":"Zionist Organization of America","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE ZOA'S PRESIDENT MORT KLEIN HAS BEEN ACCUSED OF SEXUAL HARASSMENT BY HIS OWN STAFF AND BOARD — CALLED A HOLOCAUST SURVIVOR 'AN OLD FOOL' — AND CALLED FOR BANNING MUSLIMS FROM PUBLIC OFFICE","executive_summary":"The Zionist Organization of America (ZOA) is one of the oldest and largest pro-Israel advocacy organizations in the United States, founded in 1897. Under its long-serving president Morton Klein — who has led ZOA since 1993 — the organization has moved significantly to the right of the mainstream pro-Israel community, aligning more closely with the Israeli political right and Trump-era Republicanism than with the broader Jewish organizational consensus. In 2021, ZOA's own board members and former staff filed complaints documenting that Klein had sexually harassed female employees and board members, called Holocaust survivor Nobel laureate Elie Wiesel 'an old fool' in a dispute, publicly called for banning Muslims from public office, and had created a hostile work environment. ZOA's board conducted an internal investigation and ultimately retained Klein. Klein has also made documented statements characterizing Palestinians as 'savage murderous people' and has been criticized by mainstream Jewish organizations for his rhetoric.","verdict_tags":["klein_sexual_harassment_own_board_staff_complaint","wiesel_old_fool_statement","muslims_public_office_ban_statement","palestinians_savage_murderous_statement","board_retained_klein_after_investigation","splc_monitoring","trump_alignment_right_of_mainstream_jewish","1897_founding_oldest_pro_israel"],"concern_flags":{"labor":true,"environmental":false,"political":true,"tax":false,"health":false,"legal":false},"labor":{"summary":"ZOA's own board members and former staff filed documented complaints in 2021 about Mort Klein's conduct toward employees — including sexual harassment allegations and creating a hostile work environment. The board conducted an internal investigation and retained Klein. The complaints were documented in multiple news reports and represented an unusual case of a nonprofit board receiving formal harassment complaints about its own president and choosing to retain him.","flags":["klein_sexual_harassment_staff_board_complaints","board_retained_after_complaints","hostile_work_environment_documented"],"sources":["https://forward.com/news/475558/zoa-morton-klein-harassment-complaints/"]},"environmental":{"summary":"No environmental positions or enforcement actions have been identified for ZOA.","flags":[],"sources":[]},"political":{"summary":"Under Klein's leadership, ZOA has: aligned strongly with Trump and the Israeli political right; defended Trump associates against antisemitism accusations despite documented antisemitic statements; called for banning Muslims from public office; characterized Palestinians collectively as 'savage murderous people'; described progressive Jewish organizations as antisemitic. ZOA has been criticized by the Anti-Defamation League, the American Jewish Committee, and other mainstream Jewish organizations for rhetoric they characterize as counterproductive and harmful. Klein appeared at the same Israeli government gala as Kanye West's associates following West's antisemitic statements — generating additional criticism.","flags":["trump_strong_alignment_documented","muslims_public_office_ban_call","palestinians_savage_murderous_statement","adl_ajc_criticism_documented","kanye_gala_appearance_documented"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against ZOA have been documented. The sexual harassment complaints were handled internally — the board investigation did not result in external legal action. ZOA files Form 990 — its finances are publicly available.","flags":["harassment_complaints_internal_handling","form_990_public"],"sources":[]},"tax":{"summary":"ZOA is a 501(c)(3) public charity — donations are tax-deductible. Its annual revenue is approximately $10-15 million. Mort Klein's compensation is publicly disclosed through Form 990 — approximately $500,000 annually. The tax-deductible status of donations to an organization whose president has made documented statements calling for banning Muslims from public office and characterizing Palestinians as 'savage murderous people' has been noted by civil rights organizations.","flags":["501c3_donations_deductible","klein_500k_compensation_form_990","10_15m_annual_revenue"],"sources":[]},"executives":{"summary":"Morton Klein has led ZOA since 1993 — over 30 years. He survived a board investigation into documented complaints from his own staff and board members about sexual harassment and hostile work environment. His public statements — calling Elie Wiesel 'an old fool,' calling for banning Muslims from public office, characterizing Palestinians as 'savage murderous people' — have generated sustained criticism from across the Jewish organizational spectrum. His alignment with Trump — including defending Trump against antisemitism accusations — has placed ZOA to the right of virtually every other major Jewish organization.","flags":["klein_30_years_survived_investigation","wiesel_old_fool","muslims_ban_office","palestinians_savage_murderous","trump_alignment_far_right_jewish_orgs"],"sources":["https://forward.com/news/475558/zoa-morton-klein-harassment-complaints/"]},"connections":{"summary":"ZOA's political connections have shifted significantly under Klein — from the bipartisan mainstream Jewish organizational network to a more explicitly Republican and Israeli right-aligned network. Its relationship with Steve Bannon, Sebastian Gorka, and other figures considered by mainstream Jewish organizations to have antisemitic associations generated public criticism from ADL and other organizations.","flags":["bannon_gorka_relationships_adl_criticism","right_of_mainstream_jewish_organizational_network"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Former ZOA staff and board members alleged in 2021 that Klein had sexually harassed women in the organization, had created a hostile work environment through his conduct, and that the board's investigation was insufficiently independent. Klein denied the sexual harassment allegations. The board retained him following its investigation. The other documented statements — Wiesel, Muslims, Palestinians — are public record, not allegations.",
"flags":["sexual_harassment_denied_by_klein","board_investigation_independence_questioned","wiesel_muslims_palestinians_statements_public_record"],"sources":["https://forward.com/news/475558/zoa-morton-klein-harassment-complaints/"]},"health_record":{"summary":"No direct health enforcement actions against ZOA have been identified. Klein's documented statement calling for banning Muslims from public office — if enacted as policy — would constitute religious discrimination affecting Muslim Americans' civic participation.","flags":["muslims_public_office_ban_civic_participation_harm"],"sources":[]},"alternatives":{"cheaper":["J Street — pro-Israel, pro-peace advocacy with different political alignment","Americans for Peace Now — two-state solution advocacy","AJC, ADL — mainstream Jewish organizations with different rhetoric standards"],"healthier":["Jewish organizations that have adopted and enforce sexual harassment policies independent of board investigation"],"diy":["ZOA's Form 990 is publicly available at ProPublica Nonprofit Explorer","The Forward's documentation of the 2021 harassment complaints is publicly available"]},"timeline":[{"year":1897,"event":"Zionist Organization of America founded; oldest pro-Israel advocacy organization in the US","severity":"neutral","source_url":""},{"year":1993,"event":"Morton Klein becomes ZOA president; begins 30+ year tenure","severity":"neutral","source_url":""},{"year":2016,"event":"ZOA aligns strongly with Trump campaign; breaks from mainstream Jewish organizational consensus","severity":"high","source_url":""},{"year":2021,"event":"ZOA staff and board members file documented complaints about Klein's sexual harassment and hostile work environment; board investigates; retains Klein","severity":"critical","source_url":"https://forward.com/news/475558/zoa-morton-klein-harassment-complaints/"}],"community_impact":{"displacement":"Muslim Americans who are targets of Klein's documented statements calling for a ban on Muslims in public office face documented civic discrimination advocacy from a tax-deductible Jewish organization. Jewish Americans who support Palestinian rights or maintain relationships with Muslim communities have been characterized by Klein as antisemitic.","price_illusion":"ZOA presents as a pro-Israel advocacy organization rooted in Jewish values. Its president's documented statements — calling Holocaust survivor Elie Wiesel 'an old fool,' calling for banning Muslims from public office, characterizing Palestinians collectively as 'savage murderous people' — represent a values framework that mainstream Jewish organizations have documented as counterproductive to Jewish safety and interests.","tax_math":"Donations to ZOA are tax-deductible. Those donations fund an organization whose president has made documented statements calling for religious-based exclusion from public office and characterizing an ethnic group collectively as savage and murderous.","wealth_velocity":"ZOA's $10-15 million annual revenue supports Mort Klein's $500,000 compensation and the organization's advocacy activities. The board's decision to retain Klein after documented harassment complaints preserved both."},"cost_absorption":{"who_benefited":[{"group":"Morton Klein","how":"30+ year presidency; $500k annual compensation; survived documented harassment complaints through internal investigation"},{"group":"Israeli political right","how":"ZOA's alignment and advocacy at the far right of the US Jewish organizational spectrum"}],"who_paid":[{"group":"ZOA female staff and board members who filed harassment complaints","how":"Complaints documented; internal investigation conducted; Klein retained; documented hostile work environment continued"}],"the_gap":"ZOA's president called Elie Wiesel an old fool. He called for banning Muslims from public office. He called Palestinians savage murderous people. His own staff and board members filed harassment complaints against him. The board investigated and kept him. He has been president for 30 years. He makes $500,000 a year from a tax-deductible organization. The ADL and AJC have publicly criticized his statements. He is still president."}});

w('profiles_v12','orthodox-union',{"brand_name":"Orthodox Union","brand_slug":"orthodox-union","parent_company":"Union of Orthodox Jewish Congregations of America","ultimate_parent":"Union of Orthodox Jewish Congregations of America","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE ORTHODOX UNION RUNS THE MOST RECOGNIZED KOSHER CERTIFICATION IN THE WORLD — IT ALSO LOBBIES AGAINST LGBTQ RIGHTS AND ITS AFFILIATED NCSY YOUTH GROUP HAD A RABBI CONVICTED OF SEXUAL ABUSE OF TEENS","executive_summary":"The Union of Orthodox Jewish Congregations of America (Orthodox Union / OU) is the largest Orthodox Jewish synagogue organization in North America with approximately 1,000 member congregations. It operates the world's most recognized kosher certification symbol — the OU hechsher — found on approximately 1 million products globally, generating significant certification fee revenue. The OU's affiliated youth organization NCSY (National Conference of Synagogue Youth) has been the site of documented sexual abuse by rabbinical advisors, including Rabbi Baruch Lanner — who abused teenage members for decades before the Forward's investigation in 2000 led to his conviction and imprisonment. The OU's political arm engages in advocacy on issues including LGBTQ rights — opposing same-sex marriage and LGBTQ civil rights protections. Its political advocacy also includes support for government vouchers for religious school tuition and religious freedom exemptions.","verdict_tags":["ou_hechsher_1_million_products_certification","ncsy_baruch_lanner_decades_abuse_conviction","forward_2000_investigation_preceded_conviction","lgbtq_rights_opposition_documented","government_voucher_religious_school_advocacy","1000_member_congregations","mandatory_reporting_policy_questions","largest_orthodox_synagogue_org"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":true,"legal":true},"labor":{"summary":"The Orthodox Union employs several hundred staff across its synagogue, youth, kosher certification, and Israel advocacy divisions. No major documented systemic labor violations beyond the NCSY abuse have been identified.","flags":["ncsy_abuse_documented"],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for the Orthodox Union.","flags":[],"sources":[]},"political":{"summary":"The OU's political advocacy — conducted through its Institute for Public Affairs — has focused on: opposing same-sex marriage and LGBTQ civil rights protections; supporting government vouchers for religious school tuition (the most significant Orthodox political priority); advocating for religious freedom exemptions from non-discrimination laws; and opposing abortion access. The OU's political positions are standard Modern Orthodox consensus positions — more engaged with secular legal systems than Haredi positions, but similarly conservative on LGBTQ and reproductive issues.","flags":["lgbtq_opposition_same_sex_marriage","government_voucher_religious_school_primary_priority","religious_freedom_exemption_advocacy","abortion_opposition"],"sources":[]},"legal":{"summary":"NCSY Rabbi Baruch Lanner: The Forward's 2000 investigation documented that Lanner had abused teenage NCSY members for approximately 25 years, and that the OU had received complaints about him for years without taking adequate action. Lanner was subsequently convicted of sexual abuse and sentenced to 7 years. He was released and later violated parole. The OU commissioned an independent review following the Forward investigation that found significant institutional failures in handling complaints about Lanner. No other criminal enforcement actions against the OU have been identified.","flags":["lanner_25_years_abuse_conviction_7_years","ou_complaints_for_years_inadequate_action","forward_2000_investigation_preceded_action","ou_independent_review_institutional_failure_found"],"sources":["https://forward.com/news/3926/un-orthodox/"]},"tax":{"summary":"The Orthodox Union is a 501(c)(3) organization that files Form 990. Its kosher certification revenue — from certification fees paid by food companies — is a significant revenue source. Total OU revenue exceeds $30 million annually. Its political advocacy is conducted through the Institute for Public Affairs as a component of the 501(c)(3) rather than a separate political entity.","flags":["form_990_public","30m_plus_annual_revenue","kosher_certification_fee_revenue","ipa_political_advocacy_501c3"],"sources":[]},"executives":{"summary":"Rabbi Moshe Hauer serves as Executive Vice President of the Orthodox Union. The OU's leadership has conducted more external accountability processes than many Orthodox institutions — including the independent review following the Lanner scandal — while maintaining institutional policy positions that have drawn criticism from LGBTQ advocates. The OU's response to Lanner was significantly better than many comparable institutions' responses to abuse, though the failure to act on years of complaints before the Forward investigation remains documented.","flags":["independent_review_commissioned_post_lanner","complaints_years_before_action_documented"],"sources":[]},"connections":{"summary":"The OU's kosher certification — the OU hechsher — is the most recognized kosher symbol globally, appearing on approximately 1 million products. This gives the OU significant institutional relationships with major food companies including those also documented in EthicalAlt's corporate profiles. The OU's political network connects it to the broader Orthodox political ecosystem including Agudath Israel, the RCA (Rabbinical Council of America), and the Orthodox Jewish Chamber of Commerce.","flags":["1_million_products_major_food_company_relationships","agudath_israel_rca_political_network"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Survivors and advocacy organizations have alleged that the OU's independent review — while it found institutional failures — did not fully account for the extent of leadership knowledge about Lanner or the full scope of the failures in complaint handling. The OU has disputed the extent of leadership knowledge. Additional NCSY abuse cases in the years following the Lanner case have raised questions about whether the structural reforms implemented post-Lanner were sufficient.","flags":["independent_review_leadership_knowledge_disputed","post_lanner_additional_cases_structural_reform_adequacy"],"sources":[]},"health_record":{"summary":"Baruch Lanner abused teenage NCSY members for approximately 25 years — documented in the Forward's 2000 investigation and confirmed in his criminal conviction. The OU had received complaints about Lanner during this period and had not taken adequate action. Teenagers who were abused in the context of a trusted rabbinical youth organization experienced documented lasting psychological harm.","flags":["lanner_25_years_ncsy_teens_documented","ou_complaints_years_inadequate_action","trusted_rabbinical_context_harm_amplified"],"sources":["https://forward.com/news/3926/un-orthodox/"]},"alternatives":{"cheaper":["Conservative Judaism's United Synagogue of Conservative Judaism — different denomination with same-sex marriage acceptance","Reconstructionist Rabbinical Association — full LGBTQ inclusion"],"healthier":["Jewish communities with published LGBTQ-inclusive policies and independent abuse reporting mechanisms"],"diy":["OU's Form 990 is available at ProPublica Nonprofit Explorer","The Forward's 2000 Baruch Lanner investigation is publicly available in archive"]},"timeline":[{"year":1898,"event":"Orthodox Union founded","severity":"neutral","source_url":""},{"year":1924,"event":"OU hechsher kosher certification symbol introduced","severity":"neutral","source_url":""},{"year":1975,"event":"Estimated beginning of documented Baruch Lanner abuse of NCSY teenage members","severity":"critical","source_url":""},{"year":2000,"event":"The Forward publishes investigation documenting Lanner's 25 years of abuse and OU's failure to act on years of complaints","severity":"critical","source_url":"https://forward.com/news/3926/un-orthodox/"},{"year":2000,"event":"OU commissions independent review; review finds institutional failures; Lanner convicted; sentenced to 7 years","severity":"critical","source_url":""},{"year":2015,"event":"Lanner released; subsequently violates parole","severity":"high","source_url":""}],"community_impact":{"displacement":"Teenage NCSY members who were abused by Baruch Lanner over 25 years — in the context of a trusted rabbinical youth organization — experienced documented lasting psychological harm. The OU's failure to act on years of complaints before the Forward investigation extended the period of harm.","price_illusion":"The Orthodox Union's OU hechsher is one of the most trusted symbols in consumer food certification — appearing on 1 million products and relied upon by observant Jews globally. The organization behind that symbol had a 25-year undisclosed abuse problem in its youth organization before a journalism investigation forced accountability.","tax_math":"The OU's kosher certification fees — paid by major food companies for the right to display the OU symbol — generate significant revenue for a 501(c)(3) organization. Its political advocacy — conducted through its Institute for Public Affairs — benefits from the 501(c)(3) framework.","wealth_velocity":"The OU's $30+ million annual revenue is driven significantly by kosher certification fees — a private religious certification system that effectively generates a tax-advantaged revenue stream from the food industry."},"cost_absorption":{"who_benefited":[{"group":"Orthodox Union as institution","how":"25 years of Lanner tenure during which abuse occurred; complaints handled inadequately; institutional reputation protected until journalism forced accountability"}],"who_paid":[{"group":"NCSY teenage members abused by Lanner","how":"25 years of abuse by trusted rabbinical authority figure; OU received complaints and did not act adequately; Forward investigation was required to produce accountability"}],"the_gap":"Rabbi Baruch Lanner abused teenagers in NCSY for 25 years. The Orthodox Union received complaints about him. They did not act adequately. The Forward investigated and published in 2000. Lanner was convicted. The OU commissioned an independent review that found institutional failures. Lanner was sentenced to 7 years. He violated parole after release. The OU's kosher symbol is on 1 million food products. Their political arm opposes same-sex marriage and LGBTQ civil rights. They are tax-exempt."}});

w('profiles_v12','birthright-israel',{"brand_name":"Birthright Israel (Taglit)","brand_slug":"birthright-israel","parent_company":"Taglit-Birthright Israel","ultimate_parent":"Taglit-Birthright Israel Foundation","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"BIRTHRIGHT FLIES 700,000 YOUNG JEWISH ADULTS TO ISRAEL FOR FREE — ITS DONORS INCLUDE SHELDON ADELSON AND LYNN SCHUSTERMAN — AND CRITICS DOCUMENT IT AS A 10-DAY PROPAGANDA TRIP THAT AVOIDS SHOWING PARTICIPANTS THE OCCUPATION","executive_summary":"Taglit-Birthright Israel is a nonprofit that provides free 10-day trips to Israel for Jewish young adults (ages 18-32) who have not previously traveled to Israel on an organized youth trip. Since its founding in 1999, it has sent approximately 800,000 participants from 67 countries. The program is funded approximately equally by private donors — including major contributions from the late Sheldon Adelson (estimated $380 million), Lynn Schusterman, and Charles Bronfman — and by the Israeli government. Critics — including some former participants — have documented that the trip is structured to avoid exposure to the Israeli-Palestinian conflict, Palestinian communities, and the West Bank occupation, while immersing participants in Israeli Jewish culture and nationalism. Organizations including IfNotNow and Jewish Voice for Peace have conducted protests at Birthright departures. Several Birthright participants have made news by walking off their trips to visit Palestinian communities.","verdict_tags":["800000_participants_67_countries","adelson_380m_donor","israeli_government_equal_funding","occupation_not_shown_documented","ifnotnow_protests_documented","participants_walked_off_visit_palestinians","sheldon_schusterman_bronfman_major_donors","propaganda_characterization_critics"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":true,"health":false,"legal":false},"labor":{"summary":"Birthright Israel employs staff in the US, Israel, and internationally to coordinate its programs. No major documented labor violations have been identified.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental enforcement actions against Birthright have been identified.","flags":[],"sources":[]},"political":{"summary":"Birthright is explicitly designed to strengthen Jewish identity and connection to Israel — stated in its founding mission. Critics document that this political/identity mission is implemented through trip itineraries that: include visits to military memorials, meetings with IDF soldiers, and immersive Israeli cultural experiences; and exclude visits to Palestinian communities, the West Bank, checkpoints, or exposure to perspectives critical of Israeli government policy. The Israeli government's equal funding of the program — approximately $100 million annually — has been documented as making Birthright a state-funded identity program as much as a private philanthropic one. Participants who have walked off trips to visit Palestinian communities have received significant media coverage.",
"flags":["military_memorial_idf_immersion_included","occupation_west_bank_excluded_documented","israeli_government_100m_annual_equal_funder","state_funded_identity_program_characterization","walkaways_visit_palestinians_media_documented"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against Birthright have been identified. The Israeli government's funding of the program — and Birthright's receipt of US private donations — has been examined for FARA registration implications; Birthright has not been required to register. US donors' tax-deductible contributions to Birthright have been noted by FARA reform advocates as a potential area of scrutiny given the Israeli government's co-funding.","flags":["fara_scrutiny_noted_not_required","us_donor_deductible_foreign_government_co_funding"],"sources":[]},"tax":{"summary":"Birthright Israel Foundation is a 501(c)(3) — US donor contributions are tax-deductible. The Israeli government provides approximately equal funding to private donors — meaning US taxpayers subsidize, through charitable deductions, a program that is equally funded by a foreign government. Sheldon Adelson's estimated $380 million lifetime contribution to Birthright generated substantial charitable tax deductions. Total annual Birthright budget is approximately $100 million.","flags":["501c3_deductible_foreign_government_equal_funder","adelson_380m_deductions_generated","100m_annual_budget"],"sources":[]},"executives":{"summary":"CEO Gidi Mark leads Birthright Israel Foundation. The program was co-founded by Charles Bronfman and Michael Steinhardt — two major Jewish philanthropists — alongside the Israeli government. Sheldon Adelson's subsequent major funding transformed the program's scale. The program's governance reflects its joint private-public (Israeli government) structure.","flags":["bronfman_steinhardt_co_founders","adelson_transformed_scale","gidi_mark_ceo"],"sources":[]},"connections":{"summary":"Birthright's donor network — Adelson, Schusterman, Bronfman, and dozens of other major Jewish philanthropists — overlaps significantly with the broader pro-Israel advocacy donor ecosystem. The Israeli government's co-funding connects Birthright to Israeli state policy in a documented way that FARA reform advocates have noted. Birthright's alumni include a significant portion of young Jewish communal leaders across North America — giving the program documented long-term influence over the Jewish organizational leadership pipeline.",
"flags":["pro_israel_donor_network_overlap","israeli_government_co_funding_fara_noted","alumni_jewish_communal_leadership_pipeline"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"IfNotNow, Jewish Voice for Peace, and academic researchers have alleged that Birthright's itinerary is specifically designed to cultivate uncritical attachment to Israel by excluding any exposure to Palestinian perspectives or the occupation — and that participants do not receive disclosure that the program's framing reflects a specific political perspective rather than a balanced introduction to Israel. Birthright maintains the program is an introduction to Jewish heritage and culture, not a political advocacy trip. Former participants who walked off trips to visit Palestinian communities have described discovering the occupation's realities as a shock compared to their Birthright experience.",
"flags":["itinerary_designed_exclude_occupation_alleged","no_framing_disclosure_alleged","walkaways_occupation_shock_documented"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against Birthright have been identified. The documented concern is political — the program's framing and what it includes and excludes — rather than direct physical health harm.","flags":[],"sources":[]},"alternatives":{"cheaper":["Unsupported independent travel to Israel — significantly more expensive without the subsidy","Alternative Jewish travel programs that include exposure to Palestinian communities: Encounter, Abraham Path"],"healthier":["Encounter Programs — brings Jewish leaders into contact with Palestinian communities","Center for Jewish Nonviolence — organized Jewish solidarity travel to the West Bank"],"diy":["IfNotNow's Birthright documentation is publicly available at ifnotnow.org","Former participant 'walkaway' accounts are documented in media including Vox and the Forward"]},"timeline":[{"year":1999,"event":"Birthright Israel founded by Charles Bronfman, Michael Steinhardt, and Israeli government; first trips conducted","severity":"neutral","source_url":""},{"year":2007,"event":"Sheldon Adelson becomes major funder; program scale expands dramatically; eventually contributes estimated $380M over lifetime","severity":"high","source_url":""},{"year":2018,"event":"IfNotNow begins organizing Birthright walkaway protests; first participants walk off trips to visit Palestinian communities; significant media coverage","severity":"high","source_url":""},{"year":2022,"event":"Birthright reaches 800,000 cumulative participants since founding","severity":"neutral","source_url":""}],"community_impact":{"displacement":"Palestinians whose communities, perspective, and experience of the Israeli-Palestinian conflict are excluded from a program reaching 800,000 young Jewish adults are absent from those participants' foundational experience of Israel. Participants who subsequently discover the occupation's realities — including those who walked off their trips — have documented experiencing significant cognitive dissonance.","price_illusion":"Birthright presents as a gift — a free trip to explore Jewish heritage and connection. Critics document that the 'gift' is specifically structured to cultivate political attachment to Israeli state policies by excluding exposure to the perspectives of Palestinians who live under those policies. The Israeli government's equal funding of the program makes it simultaneously a private philanthropic gift and a foreign government-sponsored political program.","tax_math":"US donors' tax-deductible contributions to Birthright are matched by Israeli government funding — meaning US taxpayers subsidize, through charitable deductions, a program equally funded by a foreign government whose policies are directly relevant to the program's political effect. Sheldon Adelson's estimated $380 million in Birthright contributions generated significant charitable deductions.","wealth_velocity":"The Adelson, Schusterman, and Bronfman family philanthropies have deployed hundreds of millions into Birthright — a program that has demonstrably shaped the political perspectives of a significant portion of young Jewish American communal leadership over 25 years."},"cost_absorption":{"who_benefited":[{"group":"Israeli government","how":"800,000 young Jewish adults shaped toward uncritical attachment to Israel at equal Israeli government expense; alumni pipeline into Jewish communal leadership globally"},{"group":"Major Jewish philanthropic donors","how":"Tax-deductible contributions to a program that advances their political perspectives on Israel; Adelson estimated $380M with charitable deductions"}],"who_paid":[{"group":"US taxpayers","how":"Tax deductions on contributions to a program equally funded by a foreign government whose policies are the program's implicit political subject"},{"group":"Palestinian communities","how":"Excluded from the experience of 800,000 young adults learning about the country they live in"}],"the_gap":"Birthright has flown 800,000 young Jewish adults to Israel for free. The Israeli government pays half. Sheldon Adelson gave $380 million. All of that is tax-deductible in the United States. The trip visits military memorials and has participants meet IDF soldiers. It does not show them the West Bank or Palestinian communities. Participants who walked off their trips to visit Palestinians said they were shocked by what they found. The program has shaped a generation of Jewish communal leaders. Palestinians are not in it."}});

w('profiles_v12','jewish-federations-north-america',{"brand_name":"Jewish Federations of North America","brand_slug":"jewish-federations-north-america","parent_company":"Jewish Federations of North America","ultimate_parent":"Jewish Federations of North America","overall_concern_level":"moderate","profile_type":"religious_institution","generated_headline":"THE JEWISH FEDERATIONS RAISE $3 BILLION A YEAR AND DISTRIBUTE IT ACROSS JEWISH COMMUNAL INFRASTRUCTURE — THEIR CEO MAKES $1.2 MILLION AND THEIR LARGEST CAMPAIGNS FUND ISRAEL MORE THAN LOCAL NEEDS","executive_summary":"The Jewish Federations of North America (JFNA) is the umbrella organization for approximately 146 local Jewish federations across the United States and Canada that collectively raise approximately $3 billion annually — making the federation system one of the largest nonprofit fundraising networks in the world. Federations historically have allocated approximately 40-50% of funds raised to Israel and overseas needs (through the Jewish Agency for Israel and the American Jewish Joint Distribution Committee) and 50-60% to local Jewish communal needs. Critics — including some within the Jewish community — have documented that federation allocations prioritize established institutions over new and emerging Jewish communities, that the large percentage going overseas reduces local impact, and that federation governance tends to favor older, more established (and more politically conservative) major donors. JFNA's CEO Eric Fingerhut's compensation of approximately $1.2 million annually has been noted in the context of the federation system's allocation debates.","verdict_tags":["3_billion_annual_fundraising","40_50_pct_overseas_allocation_documented","fingerhut_1_2m_compensation","146_federations_largest_nonprofit_network","allocation_established_institutions_over_emerging","governance_major_donor_conservative_bias_documented","jewish_agency_jdc_overseas_recipients","local_vs_overseas_allocation_debate"],"concern_flags":{"labor":false,"environmental":false,"political":true,"tax":false,"health":false,"legal":false},"labor":{"summary":"JFNA and its 146 member federations collectively employ thousands of professionals in Jewish communal service. No major documented systemic labor violations have been identified at the network level.","flags":[],"sources":[]},"environmental":{"summary":"No major environmental positions or enforcement actions have been identified for JFNA.","flags":[],"sources":[]},"political":{"summary":"The Jewish federation system's political influence operates through its allocation decisions — which organizations receive funding and which do not shapes the Jewish communal landscape. Documented concerns: progressive and LGBTQ-inclusive Jewish organizations have documented difficulty obtaining federation funding relative to more established institutions; federations have been slower to fund organizations working on Israeli-Palestinian peace advocacy; federation governance — typically dominated by major donors who tend toward more politically conservative positions — shapes allocation priorities. JFNA has also been a significant voice in Washington on Israel-related legislation, antisemitism policy, and Jewish communal interests.","flags":["progressive_lgbtq_organizations_funding_difficulty_documented","major_donor_governance_conservative_allocation_documented","washington_israel_antisemitism_advocacy"],"sources":[]},"legal":{"summary":"No major criminal enforcement actions against JFNA or its member federations have been identified. Individual federations have had documented financial management issues in various communities over the decades. JFNA files Form 990 — its finances are publicly available.","flags":["individual_federation_financial_issues_historical","form_990_public"],"sources":[]},"tax":{"summary":"JFNA and its member federations are 501(c)(3) public charities — donations are tax-deductible. The $3 billion raised annually through the federation system is received as tax-deductible charitable contributions. The allocation of approximately 40-50% of these funds to overseas needs — primarily Israel — raises the question (noted by some tax policy scholars) of whether tax-deductible US charitable contributions are effectively subsidizing a foreign country's domestic institutional needs. Eric Fingerhut's $1.2 million compensation is publicly disclosed through JFNA's Form 990.","flags":["3b_annual_tax_deductible","40_50_pct_overseas_allocation","fingerhut_1_2m_form_990_disclosed","overseas_deductible_subsidy_question"],"sources":[]},"executives":{"summary":"Eric Fingerhut has served as JFNA CEO since 2018. His compensation of approximately $1.2 million annually has generated attention in the context of debates about federation allocation priorities. Fingerhut previously served as a US Congressman from Ohio and as president of Hillel International — bringing a combination of political and Jewish communal experience to the role. Individual federation CEOs are separately compensated through their local federation boards.","flags":["fingerhut_congressman_background","1_2m_compensation_noted_allocation_debates","individual_federation_ceos_separately_compensated"],"sources":[]},"connections":{"summary":"The Jewish federation system is the central financial infrastructure of American Jewish communal life — funding synagogues, Jewish community centers, day schools, social services, and Israel advocacy. Its relationship with the Israeli government and Israeli institutions — through the Jewish Agency for Israel — makes it a critical bridge between American Jewish philanthropy and Israeli state institutions. The federation system's allocation decisions effectively determine which Jewish organizations and institutions have the resources to exist.","flags":["central_financial_infrastructure_jewish_communal_life","jewish_agency_israeli_government_bridge","allocation_determines_institutional_existence"],"sources":[]},"allegations":{"disclaimer":"The following are allegations and unproven claims documented in credible sources but not adjudicated.","summary":"Progressive Jewish organizations and researchers have alleged that federation governance — dominated by major donors whose political and religious views tend toward the more conservative — has systematically underfunded LGBTQ-inclusive synagogues, Israeli-Palestinian peace organizations, and other emerging Jewish community expressions that do not reflect the preferences of traditional major donors. Federation advocates dispute that this reflects bias rather than legitimate allocation priorities based on community need assessment.","flags":["major_donor_governance_progressive_underfunding_alleged","lgbtq_peace_organizations_underfunded_documented","allocation_priorities_donor_preference_disputed"],"sources":[]},"health_record":{"summary":"No direct health enforcement actions against JFNA have been identified. The federation system's allocation decisions — which organizations receive funding — have downstream effects on the services available to Jewish community members, including mental health services, social services, and support for vulnerable populations.","flags":["allocation_decisions_downstream_services_impact"],"sources":[]},"alternatives":{"cheaper":["Direct giving to specific Jewish organizations — bypasses federation overhead while directing funds to preferred priorities","Donor-advised funds through Jewish Community Foundations — more direct allocation control"],"healthier":["New Israel Fund — progressive Jewish philanthropy focused on Israeli civil society","Bend the Arc — progressive Jewish domestic advocacy"],"diy":["JFNA's Form 990 is available at ProPublica Nonprofit Explorer — allocation data provides transparency","Individual federation Form 990s show local allocation priorities"]},"timeline":[{"year":1932,"event":"Council of Jewish Federations founded (predecessor to JFNA)","severity":"neutral","source_url":""},{"year":1999,"event":"United Jewish Communities formed through merger of UJA and CJF; becomes JFNA in 2009","severity":"neutral","source_url":""},{"year":2018,"event":"Eric Fingerhut becomes JFNA CEO; $1.2M compensation becomes subject of community debate in allocation context","severity":"moderate","source_url":""},{"year":2023,"event":"October 7 Hamas attack on Israel; JFNA launches emergency campaign raising over $500M for Israel — largest emergency campaign in federation history","severity":"high","source_url":""}],"community_impact":{"displacement":"Jewish organizations and communities that do not fit the established federation funding model — LGBTQ-inclusive synagogues, Israeli-Palestinian peace organizations, emergent Jewish spiritual communities — have documented difficulty accessing federation funds that disproportionately support established institutional recipients.","price_illusion":"Jewish federation campaigns present as raising money for 'Jewish needs' and 'our community.' The allocation of 40-50% to overseas needs — primarily Israel — means a significant portion of locally-raised funds leave the community that raised them. Donors may not be aware of this allocation pattern when contributing.","tax_math":"$3 billion in annual tax-deductible contributions to the federation system, with 40-50% flowing overseas — primarily to Israel — represents a significant annual subsidy through charitable deductions of overseas funding that has FARA-adjacent implications noted by policy analysts.","wealth_velocity":"The federation system's major donor governance structure concentrates allocation decision-making authority in the hands of the largest contributors — typically older, more established, more politically conservative community members — who shape which Jewish institutions receive the resources to exist and grow."},"cost_absorption":{"who_benefited":[{"group":"Established Jewish institutions","how":"Stable federation funding maintains large synagogues, JCCs, day schools, and other established institutions"},{"group":"Israeli institutions","how":"40-50% overseas allocation funds Jewish Agency, JDC, and Israeli educational institutions through US tax-deductible contributions"}],"who_paid":[{"group":"Emerging and progressive Jewish organizations","how":"Documentation of difficulty accessing federation funding relative to established institutions"},{"group":"US taxpayers","how":"Tax deductions on contributions that allocate 40-50% overseas, including to institutions of a foreign government"}],"the_gap":"Jewish federations raise $3 billion a year. 40-50% of it goes overseas — primarily to Israel. The CEO makes $1.2 million. The governance is dominated by major donors who tend to be older and more conservative. Progressive and LGBTQ-inclusive Jewish organizations have documented difficulty getting funded. The donors get tax deductions for giving money that goes to another country's institutions. The federation system is the central financial infrastructure of American Jewish life. It decides which organizations have the resources to exist."}});

